/* Force a full look up iff the parent directory has changed */
if (!nfs_is_exclusive_create(dir, flags) &&
    nfs_check_verifier(dir, dentry, flags & LOOKUP_RCU)) {

	if (nfs_lookup_verify_inode(inode, flags)) {
		if (flags & LOOKUP_RCU)
			return -ECHILD;
		goto out_zap_parent;
	}
	goto out_valid;
}

